// Simulated authentication middleware (assumes it has already run)
const simulatedAuthMiddleware = (req, res, next) => {
  // In a real app, this would be set by actual auth middleware (e.g., JWT verification)
  req.user = {
    id: '1',
    username: 'johndoe',
    role: 'user'
  };
  next();
};

app.use(simulatedAuthMiddleware);

// Helper to build a public profile (excludes sensitive fields)
function getPublicProfile(user) {
  return {
    id: user.id,
    username: user.username,
    firstName: user.firstName,
    lastName: user.lastName,
    bio: user.bio,
    avatarUrl: user.avatarUrl,
    createdAt: user.createdAt
  };
}

// Helper to build a full profile (includes email and other private fields)
function getFullProfile(user) {
  return {
    id: user.id,
    username: user.username,
    email: user.email,
    firstName: user.firstName,
    lastName: user.lastName,
    bio: user.bio,
    avatarUrl: user.avatarUrl,
    createdAt: user.createdAt,
    isPublic: user.isPublic
  };
}

// GET /api/users/:userId/profile - Returns user profile information
app.get('/api/users/:userId/profile', (req, res) => {
  try {
    const { userId } = req.params;
    const authenticatedUser = req.user;

    // Validate userId parameter
    if (!userId || typeof userId !== 'string' || userId.trim() === '') {
      return res.status(400).json({
        success: false,
        error: 'Invalid user ID parameter'
      });
    }

    // Look up the requested user
    const requestedUser = users[userId];

    if (!requestedUser) {
      return res.status(404).json({
        success: false,
        error: 'User not found'
      });
    }

    const isOwnProfile = authenticatedUser.id === userId;

    // If the authenticated user is requesting their own profile, return full profile
    if (isOwnProfile) {
      return res.status(200).json({
        success: true,
        data: {
          profile: getFullProfile(requestedUser),
          isOwnProfile: true
        }
      });
    }

    // If the profile is not public and it's not the user's own profile, deny access
    if (!requestedUser.isPublic) {
      return res.status(403).json({
        success: false,
        error: 'This user profile is private'
      });
    }

    // Return public profile for other users
    return res.status(200).json({
      success: true,
      data: {
        profile: getPublicProfile(requestedUser),
        isOwnProfile: false
      }
    });
  } catch (error) {
    console.error('Error fetching user profile:', error);
    return res.status(500).json({
      success: false,
      error: 'Internal server error'
    });
  }
});

// GET /api/me/profile - Shortcut to get the authenticated user's own profile
app.get('/api/me/profile', (req, res) => {
  try {
    const authenticatedUser = req.user;
    const user = users[authenticatedUser.id];

    if (!user) {
      return res.status(404).json({
        success: false,
        error: 'Authenticated user profile not found'
      });
    }

    return res.status(200).json({
      success: true,
      data: {
        profile: getFullProfile(user),
        isOwnProfile: true
      }
    });
  } catch (error) {
    console.error('Error fetching own profile:', error);
    return res.status(500).json({
      success: false,
      error: 'Internal server error'
    });
  }
});

